import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, readFileSync, rmSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  TEST_COMMAND_RE,
  GIT_COMMIT_RE,
  emptyMetrics,
  applyEvent,
  getMetricsPath,
  metricsBridge,
} from '../../posttool/metrics-bridge.js';
import { NOOP_CTX } from '../../lib/context.js';

describe('metrics-bridge', () => {
  describe('command regex', () => {
    test('TEST_COMMAND_RE matches test runners', () => {
      expect(TEST_COMMAND_RE.test('npm test')).toBe(true);
      expect(TEST_COMMAND_RE.test('pytest')).toBe(true);
      expect(TEST_COMMAND_RE.test('ls')).toBe(false);
    });

    test('GIT_COMMIT_RE matches git commit', () => {
      expect(GIT_COMMIT_RE.test('git commit -m "x"')).toBe(true);
      expect(GIT_COMMIT_RE.test('git status')).toBe(false);
    });
  });

  describe('emptyMetrics + applyEvent', () => {
    test('emptyMetrics returns zero counters with timestamps', () => {
      const m = emptyMetrics('abc');
      expect(m.session_id).toBe('abc');
      expect(m.edits).toBe(0);
      expect(m.test_runs).toBe(0);
      expect(m.commits).toBe(0);
      expect(m.bash_calls).toBe(0);
      expect(m.agent_spawns).toBe(0);
      expect(m.started_at).toMatch(/^\d{4}-\d{2}-\d{2}T/);
    });

    test('Write increments edits', () => {
      const m = emptyMetrics('s');
      expect(applyEvent(m, 'Write', '')).toBe(true);
      expect(m.edits).toBe(1);
    });

    test('Bash with test command increments bash_calls AND test_runs', () => {
      const m = emptyMetrics('s');
      applyEvent(m, 'Bash', 'npm test');
      expect(m.bash_calls).toBe(1);
      expect(m.test_runs).toBe(1);
    });

    test('Bash with git commit increments bash_calls AND commits', () => {
      const m = emptyMetrics('s');
      applyEvent(m, 'Bash', 'git commit -m "x"');
      expect(m.bash_calls).toBe(1);
      expect(m.commits).toBe(1);
    });

    test('Agent increments agent_spawns', () => {
      const m = emptyMetrics('s');
      applyEvent(m, 'Agent', '');
      expect(m.agent_spawns).toBe(1);
    });

    test('unknown tool is a no-op', () => {
      const m = emptyMetrics('s');
      expect(applyEvent(m, 'Read', '')).toBe(false);
      expect(m.edits).toBe(0);
    });
  });

  describe('file I/O roundtrip', () => {
    let tmp: string;
    beforeEach(() => { tmp = mkdtempSync(join(tmpdir(), 'metrics-')); });
    afterEach(() => { rmSync(tmp, { recursive: true, force: true }); });

    test('first event creates metrics file with correct shape', () => {
      const input = { tool_name: 'Write', session_id: 'sess-42', tool_input: { file_path: '/a' } } as never;
      metricsBridge(input, { ...NOOP_CTX, projectDir: tmp });
      const p = getMetricsPath(tmp, 'sess-42');
      expect(existsSync(p)).toBe(true);
      const m = JSON.parse(readFileSync(p, 'utf8'));
      expect(m.session_id).toBe('sess-42');
      expect(m.edits).toBe(1);
    });

    test('subsequent events accumulate', () => {
      const write = { tool_name: 'Write', session_id: 'sess-42', tool_input: { file_path: '/a' } } as never;
      const bash = { tool_name: 'Bash', session_id: 'sess-42', tool_input: { command: 'npm test' } } as never;
      metricsBridge(write, { ...NOOP_CTX, projectDir: tmp });
      metricsBridge(write, { ...NOOP_CTX, projectDir: tmp });
      metricsBridge(bash, { ...NOOP_CTX, projectDir: tmp });
      const m = JSON.parse(readFileSync(getMetricsPath(tmp, 'sess-42'), 'utf8'));
      expect(m.edits).toBe(2);
      expect(m.bash_calls).toBe(1);
      expect(m.test_runs).toBe(1);
    });

    test('silent for unsupported tool, no file written', () => {
      const input = { tool_name: 'Read', session_id: 'sess', tool_input: {} } as never;
      metricsBridge(input, { ...NOOP_CTX, projectDir: tmp });
      expect(existsSync(getMetricsPath(tmp, 'sess'))).toBe(false);
    });
  });
});
